import { test, expect } from '@playwright/test';

test('different click operations', async ({ page }) => {
  await page.goto('https://example.com');

  // Basic click
  await page.click('button');

  // Click with locator
  await page.locator('button').click();

  // Double click
  await page.dblclick('.item');

  // Right click (context menu)
  await page.click('.file', { button: 'right' });

  // Click with modifiers
  await page.click('a', { modifiers: ['Control'] }); // Ctrl+Click
  await page.click('a', { modifiers: ['Meta'] }); // Cmd+Click on Mac
  await page.click('a', { modifiers: ['Shift'] });

  // Click at specific position
  await page.click('canvas', { position: { x: 100, y: 200 } });

  // Force click (bypass actionability checks)
  await page.click('button', { force: true });

  // Click with timeout
  await page.click('button', { timeout: 10000 });

  // Multiple clicks
  await page.click('button', { clickCount: 3 }); // Triple click
});

test('click variations', async ({ page }) => {
  await page.goto('https://example.com');

  // Click and wait for navigation
  await Promise.all([
    page.waitForNavigation(),
    page.click('a[href="/about"]')
  ]);

  // Click if visible
  const button = page.locator('button.optional');
  if (await button.isVisible()) {
    await button.click();
  }
});

test('text input methods', async ({ page }) => {
  await page.goto('https://example.com/form');

  // fill() - Fastest method, clears then types
  await page.fill('input[name="email"]', 'user@example.com');
  await page.locator('#email').fill('user@example.com');

  // type() - Types character by character (more realistic)
  await page.type('input[name="search"]', 'Playwright', { delay: 100 });

  // Clear field
  await page.fill('input[name="email"]', '');

  // Press specific keys
  await page.press('input[name="search"]', 'Enter');
  await page.press('input', 'Control+A'); // Select all
  await page.press('input', 'Backspace');

  // Type and press Enter
  await page.fill('input[name="search"]', 'test');
  await page.press('input[name="search"]', 'Enter');

  // Focus and type
  await page.focus('input[name="username"]');
  await page.keyboard.type('testuser');
});

test('textarea handling', async ({ page }) => {
  await page.goto('https://example.com/form');

  // Multi-line text
  await page.fill('textarea', 'Line 1\nLine 2\nLine 3');

  // Append text (focus first to avoid clearing)
  await page.focus('textarea');
  await page.keyboard.type('\nLine 4');
});

test('checkbox operations', async ({ page }) => {
  await page.goto('https://example.com/form');

  // Check a checkbox
  await page.check('input[type="checkbox"]');
  await page.locator('#agree').check();

  // Uncheck a checkbox
  await page.uncheck('input[type="checkbox"]');

  // Set to specific state
  await page.setChecked('#agree', true);  // Check
  await page.setChecked('#agree', false); // Uncheck

  // Verify checkbox state
  const isChecked = await page.isChecked('#agree');
  expect(isChecked).toBe(true);

  // Toggle checkbox
  if (await page.isChecked('#agree')) {
    await page.uncheck('#agree');
  } else {
    await page.check('#agree');
  }
});

test('radio button operations', async ({ page }) => {
  await page.goto('https://example.com/form');

  // Select radio button
  await page.check('input[value="male"]');
  await page.check('input[value="female"]');

  // Using getByLabel
  await page.getByLabel('Male').check();

  // Verify selected radio
  expect(await page.isChecked('input[value="male"]')).toBe(true);
});

test('dropdown operations', async ({ page }) => {
  await page.goto('https://example.com/form');

  // Select by value
  await page.selectOption('select#country', 'usa');

  // Select by label
  await page.selectOption('select#country', { label: 'United States' });

  // Select by index
  await page.selectOption('select#country', { index: 2 });

  // Select multiple options
  await page.selectOption('select[multiple]', ['option1', 'option2', 'option3']);

  // Using locator
  await page.locator('select#country').selectOption('usa');

  // Get selected value
  const value = await page.locator('select#country').inputValue();
  console.log('Selected:', value);
});

test('custom dropdown (not select)', async ({ page }) => {
  await page.goto('https://example.com/form');

  // Custom dropdowns require click + select
  await page.click('.custom-dropdown');
  await page.click('text=Option 2');

  // Or with locators
  await page.locator('.custom-dropdown').click();
  await page.locator('.dropdown-menu').locator('text=Option 2').click();
});

test('hover operations', async ({ page }) => {
  await page.goto('https://example.com');

  // Hover over element
  await page.hover('.menu-item');

  // Hover and then click submenu
  await page.hover('.menu-item');
  await page.click('.submenu-item');

  // Hover with locator
  await page.locator('.tooltip-trigger').hover();

  // Verify element visible after hover
  await page.hover('.menu');
  await expect(page.locator('.dropdown')).toBeVisible();
});

test('focus operations', async ({ page }) => {
  await page.goto('https://example.com/form');

  // Focus an element
  await page.focus('input[name="email"]');

  // Verify focus
  const isFocused = await page.locator('input[name="email"]').evaluate(
    el => el === document.activeElement
  );
  expect(isFocused).toBe(true);

  // Tab through elements
  await page.press('body', 'Tab');
  await page.press('body', 'Tab');

  // Blur (remove focus)
  await page.locator('input[name="email"]').blur();
});

test('keyboard operations', async ({ page }) => {
  await page.goto('https://example.com');

  // Press single keys
  await page.keyboard.press('Enter');
  await page.keyboard.press('Escape');
  await page.keyboard.press('Tab');
  await page.keyboard.press('ArrowDown');

  // Keyboard shortcuts
  await page.keyboard.press('Control+A'); // Select all
  await page.keyboard.press('Control+C'); // Copy
  await page.keyboard.press('Control+V'); // Paste
  await page.keyboard.press('Meta+A'); // Cmd+A on Mac

  // Type text
  await page.keyboard.type('Hello World');

  // Hold and release keys
  await page.keyboard.down('Shift');
  await page.keyboard.press('A'); // Types 'A'
  await page.keyboard.up('Shift');

  // Insert text (paste)
  await page.keyboard.insertText('Pasted text');
});

test('keyboard navigation', async ({ page }) => {
  await page.goto('https://example.com/form');

  // Navigate form with Tab
  await page.keyboard.press('Tab');
  await page.keyboard.type('username');
  await page.keyboard.press('Tab');
  await page.keyboard.type('password');
  await page.keyboard.press('Enter'); // Submit
});

test('mouse operations', async ({ page }) => {
  await page.goto('https://example.com');

  // Move mouse
  await page.mouse.move(100, 200);

  // Click at current position
  await page.mouse.click(100, 200);

  // Double click
  await page.mouse.dblclick(100, 200);

  // Mouse down and up (for drag)
  await page.mouse.move(100, 200);
  await page.mouse.down();
  await page.mouse.move(300, 400);
  await page.mouse.up();

  // Wheel scroll
  await page.mouse.wheel(0, 100); // Scroll down
});

test('drag and drop', async ({ page }) => {
  await page.goto('https://example.com/drag-drop');

  // Method 1: Using dragTo
  await page.locator('.draggable').dragTo(page.locator('.dropzone'));

  // Method 2: Using mouse events
  const source = await page.locator('.draggable').boundingBox();
  const target = await page.locator('.dropzone').boundingBox();

  await page.mouse.move(source.x + source.width / 2, source.y + source.height / 2);
  await page.mouse.down();
  await page.mouse.move(target.x + target.width / 2, target.y + target.height / 2);
  await page.mouse.up();
});

test('file upload', async ({ page }) => {
  await page.goto('https://example.com/upload');

  // Upload single file
  await page.setInputFiles('input[type="file"]', 'path/to/file.pdf');

  // Upload multiple files
  await page.setInputFiles('input[type="file"]', [
    'path/to/file1.pdf',
    'path/to/file2.jpg'
  ]);

  // Upload with buffer
  await page.setInputFiles('input[type="file"]', {
    name: 'file.txt',
    mimeType: 'text/plain',
    buffer: Buffer.from('File content')
  });

  // Remove files
  await page.setInputFiles('input[type="file"]', []);

  // Using locator
  await page.locator('input[type="file"]').setInputFiles('file.pdf');
});

test('file download', async ({ page }) => {
  await page.goto('https://example.com/download');

  // Wait for download
  const [download] = await Promise.all([
    page.waitForEvent('download'),
    page.click('a#download-link')
  ]);

  // Save to specific path
  await download.saveAs('downloads/' + download.suggestedFilename());

  // Get download info
  console.log('Downloaded:', download.suggestedFilename());
  console.log('Path:', await download.path());

  // Verify download
  const path = await download.path();
  expect(path).toBeTruthy();
});
